                preceding = ''.join(lines[max(0,i-3):i])
                if '///' not in preceding and '//!' not in preceding:
                    undocumented.append(f'{fpath}:{i+1} — {stripped[:80]}')
if undocumented:
    print('UNDOCUMENTED pub items:')
    for u in undocumented:
        print(' ', u)
    sys.exit(1)
else:
